const SUPABASE_URL = 'https://faklxfakgzkpkbxfihzh.supabase.co';
const SUPABASE_API_KEY = 'REDACTED_SUPABASE_KEY';
const trigger = $('workflow_trigger').first().json;
const userId = trigger.user_id || '';

let recipient_email = trigger.recipient_email;
let bcc_email = trigger.bcc_email;
try {
  const rows = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/app_config_v2?key=in.(recipient_email,bcc_email)&select=key,value&user_id=eq.${encodeURIComponent(userId)}`,
    headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
  });
  for (const row of rows) {
    if (row.key === 'recipient_email' && !recipient_email) recipient_email = row.value;
    if (row.key === 'bcc_email' && !bcc_email) bcc_email = row.value;
  }
} catch (e) {
  if (!recipient_email) recipient_email = 'eric@agileadtesting.com';
}

// Load project with outline
const projectTitle = trigger.project_title || '';
let project = null;
let bookOutline = null;
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/writing_projects_v2?title=ilike.*${encodeURIComponent(projectTitle)}*&select=id,title,genre_slug,outline&limit=1&user_id=eq.${encodeURIComponent(userId)}`,
    headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
  });
  if (Array.isArray(resp) && resp.length > 0) {
    project = resp[0];
    bookOutline = resp[0].outline;
  }
} catch (e) {}

if (!project || !bookOutline || !bookOutline.chapters) {
  return [{ json: { error: true, result: 'Project "' + projectTitle + '" not found or has no book outline. Run brainstorm_story first.' } }];
}

// Load chapter story arc (may differ from book arc)
const chapterArcName = (trigger.chapter_story_arc || '').trim();
const bookArcName = bookOutline.story_arc_name || '';
const arcToLoad = chapterArcName || bookArcName;
let chapterArcPrompt = '';
let resolvedChapterArcName = '';
if (arcToLoad) {
  try {
    const arcs = await this.helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/story_arcs_v2?name=ilike.*${encodeURIComponent(arcToLoad)}*&limit=1`,
      headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
    });
    if (Array.isArray(arcs) && arcs.length > 0) {
      chapterArcPrompt = arcs[0].prompt_text;
      resolvedChapterArcName = arcs[0].name;
    }
  } catch (e) {}
}

// Also load the book's story arc if different
let bookArcPrompt = '';
if (bookArcName && bookArcName !== resolvedChapterArcName) {
  try {
    const arcs = await this.helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/story_arcs_v2?name=ilike.*${encodeURIComponent(bookArcName)}*&limit=1`,
      headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
    });
    if (Array.isArray(arcs) && arcs.length > 0) {
      bookArcPrompt = arcs[0].prompt_text;
    }
  } catch (e) {}
}

// Load genre config
let genreData = {};
if (project.genre_slug) {
  try {
    const g = await this.helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/genres_v2?genre_slug=eq.${encodeURIComponent(project.genre_slug)}&limit=1&user_id=eq.${encodeURIComponent(userId)}`,
      headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
    });
    if (Array.isArray(g) && g.length > 0) genreData = g[0];
  } catch (e) {}
}

return [{ json: {
  SUPABASE_URL, SUPABASE_API_KEY, userId,
  recipient_email, bcc_email: bcc_email || '',
  project, bookOutline, genreData,
  bookArcName, bookArcPrompt,
  chapterArcName: resolvedChapterArcName, chapterArcPrompt
} }];

const trigger = $('workflow_trigger').first().json;
const s = $('settings').first().json;

if (s.error) return [{ json: { error: true, result: s.result } }];

const bookOutline = s.bookOutline;
const genreData = s.genreData || {};
const bookArcName = s.bookArcName || 'Three-Act Structure';
const bookArcPrompt = s.bookArcPrompt || '';
const chapterArcName = s.chapterArcName || bookArcName;
const chapterArcPrompt = s.chapterArcPrompt || '';

// Parse chapter number
const rawCh = (trigger.chapter_number || '').toString().trim();
const isProl = /^(prologue|prol|0)$/i.test(rawCh);
const isEpil = /^(epilogue|epil)$/i.test(rawCh);
const chNum = isProl ? 0 : (isEpil ? -1 : parseInt(rawCh));
const chLabel = isProl ? 'Prologue' : (isEpil ? 'Epilogue' : 'Chapter ' + chNum);

// Find this chapter in the book outline
let thisChapter = null;
if (bookOutline.chapters) {
  if (isProl) {
    thisChapter = bookOutline.chapters.find(ch => ch.number === 0 || /prologue/i.test(ch.title));
  } else if (isEpil) {
    thisChapter = bookOutline.chapters.find(ch => /epilogue/i.test(ch.title) || ch.number > bookOutline.chapters.length);
  } else {
    thisChapter = bookOutline.chapters.find(ch => ch.number === chNum);
  }
}

if (!thisChapter) {
  return [{ json: { error: true, result: 'Chapter ' + rawCh + ' not found in the book outline for "' + bookOutline.title + '". Available chapters: ' + bookOutline.chapters.map(ch => ch.number + ' - ' + ch.title).join(', ') } }];
}

// Format book outline context
const charList = (bookOutline.characters || []).map(c =>
  '- ' + c.name + ' (' + c.role + '): ' + c.arc + (c.description ? ' — ' + c.description : '')
).join('\n');

const chapList = (bookOutline.chapters || []).map(ch =>
  'Ch ' + ch.number + ' — ' + ch.title + ': ' + ch.brief + (ch.arc_notes ? ' [Book Arc Beat: ' + ch.arc_notes + ']' : '')
).join('\n');

// Find surrounding chapters for context
const prevCh = bookOutline.chapters.find(ch => ch.number === (isProl ? -1 : chNum - 1));
const nextCh = bookOutline.chapters.find(ch => ch.number === (isEpil ? 999 : chNum + 1));

const instructions = trigger.instructions || '';

// Fill story arc placeholders with actual project data
const protagonist = (bookOutline.characters || []).find(c => c.role === 'Protagonist');
const protagonistDesc = protagonist ? protagonist.name + ' — ' + protagonist.arc : 'See characters in book outline';

function fillArcPlaceholders(arcText) {
  if (!arcText) return '';
  let filled = arcText;
  filled = filled.replace(/\[a full book[^\]]*\]/gi, 'a detailed chapter outline with sub-chapters');
  filled = filled.replace(/\[Book \/ Chapter[^\]]*\]/gi, 'Chapter outline');
  filled = filled.replace(/\[e\.g\., thriller[^\]]*\]/gi, genreData.genre_name || 'fiction');
  filled = filled.replace(/\[Describe briefly[^\]]*\]/gi, protagonistDesc);
  filled = filled.replace(/\[What is the core[^\]]*\]/gi, bookOutline.premise || 'See premise');
  filled = filled.replace(/\[Where and when[^\]]*\]/gi, thisChapter ? thisChapter.brief.substring(0, 100) : 'See chapter brief');
  filled = filled.replace(/\[What does the protagonist[^\]]*\]/gi, 'See book outline character arcs');
  filled = filled.replace(/\[e\.g\., 1,000 words[^\]]*\]/gi, '3-8 sub-chapter outlines of 5000 words each');
  filled = filled.replace(/\[Hero[^\]]*\]/gi, protagonistDesc);
  filled = filled.replace(/\[.*?Main character[^\]]*\]/gi, protagonistDesc);
  filled = filled.replace(/\[.*?Setting[^\]]*\]/gi, 'See chapter brief');
  filled = filled.replace(/\[.*?Length goal[^\]]*\]/gi, '3-8 sub-chapter outlines');
  filled = filled.replace(/\[.*?Genre[^\]]*\]/gi, genreData.genre_name || 'fiction');
  return filled;
}

const filledBookArc = fillArcPlaceholders(bookArcPrompt);
const filledChapterArc = fillArcPlaceholders(chapterArcPrompt);

const prompt = `You are a skilled story architect creating a detailed CHAPTER OUTLINE for ${chLabel} of "${bookOutline.title}", a ${genreData.genre_name || 'fiction'} novel.

## Your Task
Create a detailed chapter outline that breaks this chapter into SUB-CHAPTERS (mini-sections that together form the complete chapter). Each sub-chapter should be substantial enough to be a full scene or sequence. The chapter outline must serve TWO story arcs simultaneously:
1. The BOOK's story arc (${bookArcName}) — this chapter must advance the book's overall plot
2. The CHAPTER's story arc (${chapterArcName}) — this chapter has its own internal dramatic structure

## Writing Prime Directive
Write like a human, not a machine. Use clear, everyday language and short sentences. Cut cliches. Get to the point — remove filler words. Be genuine. Show, don't tell. Stay focused. Respect the reader's intelligence.

## BOOK STORY ARC — ${bookArcName}
This is the framework governing the entire book. This chapter must advance the book's position within this arc.
${filledBookArc ? '\n' + bookArcPrompt + '\n' : '(No book arc prompt loaded — use the arc_notes from the book outline below.)'}

## CHAPTER STORY ARC — ${chapterArcName}
This is the framework governing THIS CHAPTER's internal structure. Use it to organize the sub-chapters.
${filledChapterArc ? '\n' + chapterArcPrompt + '\n' : '(Same as book arc.)'}

## BOOK OUTLINE — MANDATORY CONTEXT
You MUST follow this outline. Use the EXACT character names, roles, and plot points listed.

### Premise
${bookOutline.premise || ''}

### Themes
${Array.isArray(bookOutline.themes) ? bookOutline.themes.join(', ') : (bookOutline.themes || '')}

### Characters (USE THESE EXACT NAMES AND ROLES)
${charList}

### Full Chapter Structure
${chapList}

## THIS CHAPTER'S ASSIGNMENT
**${chLabel}: ${thisChapter.title}**
Book outline brief: ${thisChapter.brief}
${thisChapter.arc_notes ? 'Book arc beat: ' + thisChapter.arc_notes : ''}
${thisChapter.research_topics ? 'Research topics: ' + thisChapter.research_topics.join(', ') : ''}

${prevCh ? '### Previous chapter context\nCh ' + prevCh.number + ' — ' + prevCh.title + ': ' + prevCh.brief : '(This is the first chapter.)'}

${nextCh ? '### Next chapter context\nCh ' + nextCh.number + ' — ' + nextCh.title + ': ' + nextCh.brief : '(This is the final chapter.)'}

${instructions ? '### User Instructions\n' + instructions : ''}

## Requirements
Create a chapter outline with the following:

1. **chapter_number**: ${isProl ? 0 : (isEpil ? bookOutline.chapters.length : chNum)}
2. **chapter_title**: The title for this chapter
3. **chapter_story_arc**: "${chapterArcName}"
4. **book_arc_beat**: Which beat/stage of the BOOK's story arc (${bookArcName}) this chapter represents
5. **chapter_summary**: 2-3 sentence summary of the entire chapter
6. **sub_chapters**: Array of sub-chapter outlines, each containing:
   - **number**: Sequential number (1, 2, 3...)
   - **title**: Sub-chapter title
   - **brief**: Detailed 3-5 sentence description of what happens in this sub-chapter. Include specific character actions, dialogue direction, emotional beats, and plot progression. This must be detailed enough that a writer can produce the full scene from this brief alone.
   - **arc_beat**: Which beat of the CHAPTER story arc (${chapterArcName}) this sub-chapter represents
   - **characters**: Array of character names who appear in this sub-chapter (use EXACT names from the book outline)
   - **setting**: Where this sub-chapter takes place
   - **emotional_tone**: The dominant emotional quality of this sub-chapter
   - **connects_to_book_arc**: How this sub-chapter advances the book's overall story arc

Create enough sub-chapters to fully realize the chapter's story — typically 3-7 sub-chapters depending on complexity. Each sub-chapter should be substantial (potentially 500-1500 words when written). Together they must cover:
- The chapter's contribution to the BOOK arc (${bookArcName})
- The chapter's own internal arc (${chapterArcName})
- All character interactions noted in the book outline for this chapter
- Scene transitions and emotional progression

Return as JSON matching the output schema exactly.`;

return [{ json: { prompt, project_id: s.project?.id, chapter_number: isProl ? 0 : (isEpil ? -1 : chNum) } }];

const s = $('settings').first().json;
const supabaseUrl = s.SUPABASE_URL;
const apiKey = s.SUPABASE_API_KEY;
const userId = s.userId || '';
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json', 'Prefer': 'return=representation' };
const readHeaders = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey };

// Handle both parsed output (from parser) and raw text (parser fallback)
let chapterOutline = $input.first().json.output || {};
if (!chapterOutline.sub_chapters || chapterOutline.sub_chapters.length === 0) {
  // Parser may have failed — try extracting JSON from raw text
  const rawText = $input.first().json.text || $input.first().json.output?.text || '';
  if (rawText) {
    try {
      const jsonMatch = rawText.match(/```json\n?([\s\S]*?)```/) || rawText.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        const parsed = JSON.parse(jsonMatch[1] || jsonMatch[0]);
        if (parsed.sub_chapters) chapterOutline = parsed;
      }
    } catch (e) { /* parse failed, continue with empty */ }
  }
}
const promptData = $('build_chapter_outline_prompt').first().json;
const projectId = s.project?.id;
// Use LLM output chapter_number, fallback to prompt data's chapter_number
const promptChNum = $('build_chapter_outline_prompt').first().json.chapter_number;
let chNum = chapterOutline.chapter_number;
if (chNum === undefined || chNum === null) chNum = promptChNum;
// Handle string "0" or "Prologue"
if (typeof chNum === 'string') {
  if (/^(prologue|prol)$/i.test(chNum)) chNum = 0;
  else if (/^(epilogue|epil)$/i.test(chNum)) chNum = -1;
  else chNum = parseInt(chNum);
}

if (!projectId) {
  return [{ json: { error: true, result: 'No project ID found.' } }];
}

// Get current outline from project
const project = s.project;
const bookOutline = s.bookOutline;

// Find the matching chapter in the book outline and add chapter_outline to it
let updated = false;
if (bookOutline && bookOutline.chapters) {
  for (let i = 0; i < bookOutline.chapters.length; i++) {
    const ch = bookOutline.chapters[i];
    if (ch.number === chNum || ch.number === parseInt(chNum) || (chNum === 0 && (ch.number === 0 || /prologue/i.test(ch.title))) || (chNum === -1 && /epilogue/i.test(ch.title))) {
      bookOutline.chapters[i].chapter_outline = chapterOutline;
      updated = true;
      break;
    }
  }
}

if (!updated) {
  return [{ json: {
  error: true,
  result: 'Could not find chapter ' + chNum + ' in the book outline to save chapter outline. Available chapters: ' + bookOutline.chapters.map(ch => ch.number + '-' + ch.title).join(', '),
  chapterOutline: chapterOutline,
  emailBody: '<h2>Error: Chapter ' + chNum + ' not found in book outline</h2><p>Available chapters: ' + bookOutline.chapters.map(ch => ch.number + ' - ' + ch.title).join(', ') + '</p>',
  title: bookOutline.title || '',
  chapterTitle: 'Error',
  subChapterCount: 0
} }];
}

// Save updated outline back to project
await this.helpers.httpRequest({
  method: 'PATCH',
  url: supabaseUrl + '/rest/v1/writing_projects_v2?id=eq.' + projectId + '&user_id=eq.' + encodeURIComponent(userId),
  headers,
  body: { outline: bookOutline, updated_at: new Date().toISOString() }
});

// Format for email
const subChList = (chapterOutline.sub_chapters || []).map(sc =>
  '<h3>Sub-chapter ' + sc.number + ': ' + sc.title + '</h3>' +
  '<p><strong>Arc Beat (' + (chapterOutline.chapter_story_arc || '') + '):</strong> ' + (sc.arc_beat || '') + '</p>' +
  '<p><strong>Characters:</strong> ' + (sc.characters || []).join(', ') + '</p>' +
  '<p><strong>Setting:</strong> ' + (sc.setting || '') + '</p>' +
  '<p><strong>Emotional Tone:</strong> ' + (sc.emotional_tone || '') + '</p>' +
  '<p>' + (sc.brief || '') + '</p>' +
  '<p><em>Book Arc Connection:</em> ' + (sc.connects_to_book_arc || '') + '</p>'
).join('<hr>');

const emailBody = '<h1>Chapter Outline: ' + (chapterOutline.chapter_title || 'Chapter ' + chNum) + '</h1>' +
  '<p><strong>Book:</strong> ' + bookOutline.title + '</p>' +
  '<p><strong>Book Story Arc:</strong> ' + (s.bookArcName || 'Not specified') + '</p>' +
  '<p><strong>Chapter Story Arc:</strong> ' + (chapterOutline.chapter_story_arc || 'Same as book') + '</p>' +
  '<p><strong>Book Arc Beat:</strong> ' + (chapterOutline.book_arc_beat || '') + '</p>' +
  '<h2>Chapter Summary</h2><p>' + (chapterOutline.chapter_summary || '') + '</p>' +
  '<h2>Sub-Chapters (' + (chapterOutline.sub_chapters || []).length + ')</h2>' + subChList;

return [{ json: { 
  chapterOutline, 
  emailBody, 
  title: bookOutline.title,
  chapterTitle: chapterOutline.chapter_title || 'Chapter ' + chNum,
  subChapterCount: (chapterOutline.sub_chapters || []).length,
  result: 'Chapter outline created for "' + (chapterOutline.chapter_title || 'Chapter ' + chNum) + '" with ' + (chapterOutline.sub_chapters || []).length + ' sub-chapters using ' + (chapterOutline.chapter_story_arc || 'default') + ' story arc. Saved to project outline and emailed for review.'
} }];
